function solve(s) {
    // Step 1: Calculate frequencies
    const freq = new Map();
    for (const char of s) {
        freq.set(char, (freq.get(char) || 0) + 1);
    }

    // Helper function to determine the mirror character
    const getMirror = (c) => {
        const charCode = c.charCodeAt(0);

        // Check for lowercase letters ('a' = 97, 'z' = 122)
        if (charCode >= 97 && charCode <= 122) {
            const pos = charCode - 97; // 0 to 25
            const mirroredPos = 25 - pos;
            return String.fromCharCode(97 + mirroredPos);
        }

        // Check for digits ('0' = 48, '9' = 57)
        if (charCode >= 48 && charCode <= 57) {
            const digit = parseInt(c); // 0 to 9
            const mirroredDigit = 9 - digit;
            return String(mirroredDigit);
        }

        // Should not be reached based on problem constraints
        return c;
    };

    let totalDifferenceSum = 0;
    const processedPairs = new Set();

    // Step 2: Iterate over unique characters in s to find unique pairs
    for (const c of freq.keys()) {
        const m = getMirror(c);

        // Create a canonical key for the pair (c, m) to ensure we count each pair only once
        // We sort them lexicographically
        const key = c < m ? `${c}-${m}` : `${m}-${c}`;

        if (processedPairs.has(key)) {
            continue;
        }

        processedPairs.add(key);

        // Get frequencies. If a character doesn't exist in s, its frequency is 0.
        const freqC = freq.get(c); // Guaranteed to exist since we iterate over freq.keys()
        const freqM = freq.get(m) || 0;

        // Calculate the absolute difference and add to the sum
        const difference = Math.abs(freqC - freqM);
        totalDifferenceSum += difference;
    }

    return totalDifferenceSum;
}

