        let mirrored_pos = 25 - pos;
        // Convert back to char
        (b'a' + mirrored_pos) as char
    } 
    // Check for digits ('0' = 48, '9' = 57)
    else if c.is_ascii_digit() {
        // Calculate digit value (0 for '0', 9 for '9')
        let digit = (c as u8) - (b'0');
        // Calculate mirrored digit value (9 - digit)
        let mirrored_digit = 9 - digit;
        // Convert back to char
        (b'0' + mirrored_digit) as char
    } else {
        // Should not happen based on problem constraints
        c
    }
