fn solve(s: String) -> i64 {
    // Step 1: Calculate frequencies
    let mut freq: HashMap<char, i64> = HashMap::new();
    for c in s.chars() {
        *freq.entry(c).or_insert(0) += 1;
    }

    let mut total_difference_sum: i64 = 0;
    // Store canonical pairs (c1, c2) where c1 <= c2 lexicographically
    let mut processed_pairs: HashSet<(char, char)> = HashSet::new();

    // Step 2: Iterate over unique characters present in s
    for &c in freq.keys() {
        let m = get_mirror(c);

        // Determine the canonical pair (c1, c2)
        let (c1, c2) = if c <= m {
            (c, m)
        } else {
            (m, c)
        };

        // Check if this pair has already been processed
        if processed_pairs.contains(&(c1, c2)) {
            continue;
        }

        // Process the pair
        processed_pairs.insert((c1, c2));

        // Get frequencies. Use unwrap_or(&0) because the mirror character m might not exist in s.

        // f1 = freq(c1). Since c1 is either c or m, if c1 comes from c, it exists. If c1=m, it might not exist.
        let f1 = *freq.get(&c1).unwrap_or(&0);
        // f2 = freq(c2)
        let f2 = *freq.get(&c2).unwrap_or(&0);

        // Calculate the absolute difference and add to the sum
        let difference = (f1 - f2).abs();

        total_difference_sum += difference;
    }

    total_difference_sum
}

