use std::collections::{HashMap, HashSet};

fn get_mirror(c: char) -> char {
    if c.is_ascii_lowercase() {
        // Lowercase letters: 'a' (97) to 'z' (122)
        let a_val = 'a' as u8;
        let z_val = 'z' as u8;
        let c_val = c as u8;

        // Position from 'a': c_val - a_val
        // Mirrored position from 'z': z_val - c_val
        // New char value: a_val + (z_val - c_val)

        // Equivalent calculation:
        // pos = c_val - a_val
        // mirrored_pos = 25 - pos
        // new_val = a_val + mirrored_pos

        // 26 characters total. Total span is 25.
        // (a + z) - c = 2 * midpoint - c
        // In ASCII: 97 + 122 = 219. 219 - c_val.

        let mirrored_code = (a_val as i32 + z_val as i32) - (c as i32);
        (mirrored_code as u8) as char
    } else if c.is_ascii_digit() {
        // Digits: '0' (48) to '9' (57)
        let zero_val = '0' as u8;
        let nine_val = '9' as u8;
        let c_val = c as u8;

        // Sum of boundaries: 48 + 57 = 105
        // Mirrored code: 105 - c_val
        let mirrored_code = (zero_val as i32 + nine_val as i32) - (c as i32);
        (mirrored_code as u8) as char
    } else {
        c // Should not happen based on constraints
    }
}

fn solve(s: String) -> i64 {
    // Step 1: Calculate frequencies
    let mut freq: HashMap<char, i64> = HashMap::new();
    for c in s.chars() {
        *freq.entry(c).or_insert(0) += 1;
    }

    let mut total_difference_sum: i64 = 0;
    let mut processed_pairs: HashSet<String> = HashSet::new();

    // Step 2: Iterate over unique characters in s
    for c in freq.keys() {
        let m = get_mirror(*c);

        // Create a canonical key for the pair {c, m}
        // Since c != m, we sort them lexicographically.
        let (key1, key2) = if *c <= m {
            (c, m)
        } else {
            (m, *c)
        };

        // Convert to String for hashing/comparison
        let key = format!("{}{}", key1, key2);

        if processed_pairs.contains(&key) {
            continue;
        }

        processed_pairs.insert(key);

        // Get frequencies. 
        // freqC is guaranteed to exist.
        let freq_c = *freq.get(c).unwrap(); 

        // freqM might not exist in the map, so default to 0.
        let freq_m = *freq.get(&m).unwrap_or(&0); 

        // Calculate the absolute difference and add to the sum
        let difference = (freq_c - freq_m).abs();
        total_difference_sum += difference;
    }

    total_difference_sum
}
